TypeScript via @tabviz/core, rendered in the browser


Code
core = import(`https://esm.sh/@tabviz/core@${tabviz_core_version}?deps=svelte@${svelte_version}`)

// Transpose the column-oriented kpi data + ensure trend is a per-row array.
kpi_rows = {
  const cols = transpose(kpi_in);
  // `kpi.trend` was set R-side via `kpi$trend &lt;- I(sales_trend)` — a
  // list-column with one 12-element numeric vector per row. Quarto's
  // `ojs_define()` + jsonlite serializes that as a nested array, so
  // `kpi_in.trend[i]` is already the per-row series; no flat slicing
  // needed.
  return cols.map((row, i) =&gt; ({
    ...row,
    trend: kpi_in.trend[i],
  }));
}

styleHref = `https://esm.sh/@tabviz/core@${tabviz_core_version}/dist/style.css`
_styleInjected = {
  if (!document.querySelector(`link[href="${styleHref}"]`)) {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = styleHref;
    document.head.appendChild(link);
  }
  return true;
}

tsWidget = {
  const { tabviz, createTabviz,
          colCurrency, colBar, colSparkline, colBadge, colStars, colRing } = await core;
  _styleInjected;

  const spec = tabviz({
    data: kpi_rows,
    label: "region",
    labelHeader: "Region",
    theme: "cochrane",
    columns: [
      colCurrency({ field: "revenue", header: "Revenue", symbol: "$",
                    decimals: 0, thousandsSep: ",", abbreviate: true }),
      colBar({ field: "growth", header: "YoY growth", scale: "linear" }),
      colSparkline({ field: "trend", header: "12-month trend", type: "area" }),
      colBadge({ field: "health", header: "Health" }),
      colStars({ field: "satisfaction", header: "CSAT", maxStars: 5 }),
      colRing({ field: "pipeline_pct", header: "Pipeline", minValue: 0, maxValue: 1 }),
    ],
    title: "Regional sales KPIs",
    caption: "Quarter-end snapshot. Revenue abbreviated; sparkline shows last 12 months.",
  });

  const host = document.createElement("div");
  host.style.minHeight = "240px";
  createTabviz(host, spec);
  return host;
}











































NoteThe pure-TypeScript snippet (for a Vite / Next.js project)





import {
  tabviz, createTabviz,
  colCurrency, colBar, colSparkline, colBadge, colStars, colRing,
} from "@tabviz/core";
import "@tabviz/core/style.css";

declare const kpiData: Array&lt;{
  region: string;
  revenue: number;
  growth: number;
  trend: number[];          // 12-month sparkline series
  health: "green" | "amber" | "red";
  satisfaction: number;     // 0-5 stars
  pipeline_pct: number;     // 0-1
}&gt;;

const spec = tabviz({
  data: kpiData,
  label: "region",
  labelHeader: "Region",
  theme: "cochrane",
  columns: [
    colCurrency({ field: "revenue", header: "Revenue", symbol: "$",
                  decimals: 0, thousandsSep: ",", abbreviate: true }),
    colBar({ field: "growth", header: "YoY growth", scale: "linear" }),
    colSparkline({ field: "trend", header: "12-month trend", type: "area" }),
    colBadge({ field: "health", header: "Health" }),
    colStars({ field: "satisfaction", header: "CSAT", maxStars: 5 }),
    colRing({ field: "pipeline_pct", header: "Pipeline",
              minValue: 0, maxValue: 1 }),
  ],
  title: "Regional sales KPIs",
});

createTabviz(document.querySelector("#plot")!, spec);

TypeScript via @tabviz/core, rendered in the browser
Below is the same plot built from the TypeScript-mirror of the R API and mounted by createTabviz — executed live in this page (no R involved). The package is loaded from esm.sh; Svelte’s optional peer dep is resolved transitively.


Code
core = import(`https://esm.sh/@tabviz/core@${tabviz_core_version}?deps=svelte@${svelte_version}`)

// Quarto exposes `snps_in` as a column-oriented table; transpose to rows.
rows = transpose(snps_in)

styleHref = `https://esm.sh/@tabviz/core@${tabviz_core_version}/dist/style.css`
// Inject the @tabviz/core stylesheet once per page.
_styleInjected = {
  if (!document.querySelector(`link[href="${styleHref}"]`)) {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = styleHref;
    document.head.appendChild(link);
  }
  return true;
}

tsWidget = {
  const { tabviz, createTabviz,
          colText, colNumeric, colInterval, colN, colPvalue,
          vizForest } = await core;
  _styleInjected;

  const spec = tabviz({
    data: rows,
    label: "snp",
    labelHeader: "SNP",
    theme: "lancet",
    columns: [
      colText({ field: "gene", header: "Gene" }),
      colNumeric({ field: "maf", header: "MAF", decimals: 2 }),
      colInterval({
        point: "effect", lower: "lower", upper: "upper",
        header: "Effect (95% CI)",
      }),
      colN({ field: "n_studies", header: "Studies" }),
      colPvalue({ field: "p_value" }),
      vizForest({
        point: "effect", lower: "lower", upper: "upper",
        axisLabel: "Effect estimate",
        scale: "linear",
        nullValue: 0,
      }),
    ],
    title: "Genetic associations with cardiovascular events",
    caption: "Effect = log odds ratio per allele; CI = 95%.",
  });

  const host = document.createElement("div");
  host.style.minHeight = "320px";
  createTabviz(host, spec);
  return host;
}





































The source of that ojs block, in plain TypeScript:






NoteThe TypeScript snippet (for use in a Vite/Next.js project)





import {
  tabviz, createTabviz,
  colText, colNumeric, colInterval, colN, colPvalue,
  vizForest,
} from "@tabviz/core";
import "@tabviz/core/style.css";

// `snpsData` is your row array — same shape as the R `snps` data.frame.
declare const snpsData: Array&lt;{
  snp: string; gene: string; maf: number;
  effect: number; lower: number; upper: number;
  n_studies: number; p_value: number;
}&gt;;

const spec = tabviz({
  data: snpsData,
  label: "snp",
  labelHeader: "SNP",
  theme: "lancet",
  columns: [
    colText({ field: "gene", header: "Gene" }),
    colNumeric({ field: "maf", header: "MAF", decimals: 2 }),
    colInterval({
      point: "effect", lower: "lower", upper: "upper",
      header: "Effect (95% CI)",
    }),
    colN({ field: "n_studies", header: "Studies" }),
    colPvalue({ field: "p_value" }),
    vizForest({
      point: "effect", lower: "lower", upper: "upper",
      axisLabel: "Effect estimate",
      scale: "linear",
      nullValue: 0,
    }),
  ],
  title: "Genetic associations with cardiovascular events",
  caption: "Effect = log odds ratio per allele; CI = 95%.",
});

const instance = createTabviz(document.querySelector("#plot")!, spec);

Web Integration

DownloadButton.svelte
The download button calls the same generator directly:
import { exportToSVG, exportToPNG } from "$lib/export";

async function handleExportSVG() {
  const svgString = exportToSVG(store.spec);
  // Create blob and trigger download
}


export.ts
Thin wrapper around svg-generator:
import { generateSVG, svgToBlob } from "./svg-generator";

export function exportToSVG(spec: WebSpec): string {
  return generateSVG(spec);
}

export async function exportToPNG(spec: WebSpec, scale = 2): Promise&lt;Blob&gt; {
  const svgString = generateSVG(spec);
  return svgToBlob(svgString, scale);  // Render to canvas, export
}

SVG Output Structure
The generated SVG follows this structure:
